from math import *
import sys

def main():
    n, money = map(int, input().split())
    a = list(map(int, input().split()))

    # We'll use a dynamic programming approach with memoization
    # dp[i][parity][m] represents the maximum cuts up to index i with current parity and m bitcoins left
    # Initialize dp with -infinity, except for the starting state

    # Since n can be up to 100 and money up to 100, and parity can be -n to n, we need to manage memory carefully
    # We'll use a dictionary or a list of dictionaries to store only necessary states

    from collections import defaultdict
    dp = [defaultdict(dict) for _ in range(n)]

    # Initial state: after first element, parity is a[0]%2 (1 or 0), money is full, cuts 0
    initial_parity = 1 if a[0] % 2 != 0 else -1
    dp[0][initial_parity][money] = 0

    max_cuts = 0

    for i in range(n - 1):
        current_parities = list(dp[i].items())
        for parity, money_dict in current_parities:
            for m in money_dict:
                current_cuts = money_dict[m]
                # Option 1: don't cut after i+1
                new_parity = parity + (1 if a[i+1] % 2 != 0 else -1)
                if new_parity in dp[i+1]:
                    if m in dp[i+1][new_parity]:
                        if current_cuts > dp[i+1][new_parity][m]:
                            dp[i+1][new_parity][m] = current_cuts
                    else:
                        dp[i+1][new_parity][m] = current_cuts
                else:
                    dp[i+1][new_parity] = {m: current_cuts}

                # Option 2: cut after i+1 if parity is 0
                if parity == 0:
                    cost = abs(a[i+1] - a[i])
                    if m >= cost:
                        new_m = m - cost
                        new_parity_cut = 1 if a[i+1] % 2 != 0 else -1
                        new_cuts = current_cuts + 1
                        if new_parity_cut in dp[i+1]:
                            if new_m in dp[i+1][new_parity_cut]:
                                if new_cuts > dp[i+1][new_parity_cut][new_m]:
                                    dp[i+1][new_parity_cut][new_m] = new_cuts
                            else:
                                dp[i+1][new_parity_cut][new_m] = new_cuts
                        else:
                            dp[i+1][new_parity_cut] = {new_m: new_cuts}

    # The answer is the maximum cuts achievable at the last index with any parity 0 and any money >=0
    max_cuts = 0
    if 0 in dp[n-1]:
        for m in dp[n-1][0]:
            if dp[n-1][0][m] > max_cuts:
                max_cuts = dp[n-1][0][m]
    print(max_cuts)

if __name__ == "__main__":
    main()
